31: ActiveTcpListener::ActiveTcpListener(Network::TcpConnectionHandler& parent,
32:                                      Network::ListenerPtr&& listener,
33:                                      Network::Address::InstanceConstSharedPtr& listen_address,
34:                                      Network::ListenerConfig& config,
