43: ActiveTcpListener::~ActiveTcpListener() {
44:   is_deleting_ = true;
45:   connection_balancer_.unregisterHandler(*this);
46: 
47:   // Purge sockets that have not progressed to connections. This should only happen when
48:   // a listener filter stops iteration and never resumes.
49:   while (!sockets_.empty()) {
50:     auto removed = sockets_.front()->removeFromList(sockets_);
51:     dispatcher().deferredDelete(std::move(removed));
52:   }
53: 
54:   for (auto& [chain, active_connections] : connections_by_context_) {
55:     ASSERT(active_connections != nullptr);
56:     auto& connections = active_connections->connections_;
57:     while (!connections.empty()) {
58:       connections.front()->connection_->close(
59:           Network::ConnectionCloseType::NoFlush,
60:           "purging_socket_that_have_not_progressed_to_connections");
61:     }
62:   }
63:   dispatcher().clearDeferredDeleteList();
64: 
65:   // By the time a listener is destroyed, in the common case, there should be no connections.
66:   // However, this is not always true if there is an in flight rebalanced connection that is
67:   // being posted. This assert is extremely useful for debugging the common path so we will leave it
68:   // for now. If it becomes a problem (developers hitting this assert when using debug builds) we
69:   // can revisit. This case, if it happens, should be benign on production builds. This case is
70:   // covered in ConnectionHandlerTest::RemoveListenerDuringRebalance.
71:   ASSERT(num_listener_connections_ == 0, fmt::format("destroyed listener {} has {} connections",
72:                                                      config_->name(), numConnections()));
73: }
