105: void ActiveTcpListener::recordConnectionsAcceptedOnSocketEvent(uint32_t connections_accepted) {
106:   stats_.connections_accepted_per_socket_event_.recordValue(connections_accepted);
107: }
108: 
109: void ActiveTcpListener::onAcceptWorker(Network::ConnectionSocketPtr&& socket,
110:                                        bool hand_off_restored_destination_connections,
111:                                        bool rebalanced,
112:                                        const absl::optional<std::string>& network_namespace) {
113:   // Get Round Trip Time
114:   absl::optional<std::chrono::milliseconds> t = socket->lastRoundTripTime();
115:   if (t.has_value()) {
116:     socket->connectionInfoProvider().setRoundTripTime(t.value());
117:   }
118: 
119:   if (!rebalanced) {
120:     Network::BalancedConnectionHandler& target_handler =
121:         connection_balancer_.pickTargetHandler(*this);
122:     if (&target_handler != this) {
123:       target_handler.post(std::move(socket));
124:       return;
125:     }
126:   }
127: 
128:   auto active_socket = std::make_unique<ActiveTcpSocket>(
129:       *this, std::move(socket), hand_off_restored_destination_connections, network_namespace);
130: 
131:   onSocketAccepted(std::move(active_socket));
132: }
