134: void ActiveTcpListener::pauseListening() {
135:   if (listener_ != nullptr) {
136:     listener_->disable();
137:   }
138: }
139: 
140: void ActiveTcpListener::resumeListening() {
141:   if (listener_ != nullptr) {
142:     listener_->enable();
143:   }
144: }
