151: void ActiveTcpListener::newActiveConnection(const Network::FilterChain& filter_chain,
152:                                             Network::ServerConnectionPtr server_conn_ptr,
153:                                             std::unique_ptr<StreamInfo::StreamInfo> stream_info) {
154:   auto& active_connections = getOrCreateActiveConnections(filter_chain);
155:   auto active_connection =
156:       std::make_unique<ActiveTcpConnection>(active_connections, std::move(server_conn_ptr),
157:                                             dispatcher().timeSource(), std::move(stream_info));
158:   // If the connection is already closed, we can just let this connection immediately die.
159:   if (active_connection->connection_->state() != Network::Connection::State::Closed) {
160:     ENVOY_CONN_LOG(
161:         debug, "new connection from {}", *active_connection->connection_,
162:         active_connection->connection_->connectionInfoProvider().remoteAddress()->asString());
163:     active_connection->connection_->addConnectionCallbacks(*active_connection);
164:     LinkedList::moveIntoList(std::move(active_connection), active_connections.connections_);
165:   }
166: }
167: 
168: void ActiveTcpListener::post(Network::ConnectionSocketPtr&& socket) {
169:   // It is not possible to capture a unique_ptr because the post() API copies the lambda, so we must
170:   // bundle the socket inside a shared_ptr that can be captured.
171:   // TODO(mattklein123): It may be possible to change the post() API such that the lambda is only
172:   // moved, but this is non-trivial and needs investigation.
173:   RebalancedSocketSharedPtr socket_to_rebalance = std::make_shared<RebalancedSocket>();
174:   socket_to_rebalance->socket = std::move(socket);
175: 
176:   dispatcher().post([socket_to_rebalance, address = listen_address_, tag = config_->listenerTag(),
177:                      &tcp_conn_handler = tcp_conn_handler_,
178:                      handoff = config_->handOffRestoredDestinationConnections()]() {
179:     auto balanced_handler = tcp_conn_handler.getBalancedHandlerByTag(tag, *address);
180:     if (balanced_handler.has_value()) {
181:       balanced_handler->get().onAcceptWorker(std::move(socket_to_rebalance->socket), handoff, true,
182:                                              address->networkNamespace());
183:       return;
184:     }
185:   });
186: }
