10: ActiveStreamListenerBase::ActiveStreamListenerBase(Network::ConnectionHandler& parent,
11:                                                    Event::Dispatcher& dispatcher,
12:                                                    Network::ListenerPtr&& listener,
13:                                                    Network::ListenerConfig& config)
14:     : ActiveListenerImplBase(parent, &config), parent_(parent),
15:       listener_filters_timeout_(config.listenerFiltersTimeout()),
16:       continue_on_listener_filters_timeout_(config.continueOnListenerFiltersTimeout()),
17:       listener_(std::move(listener)), dispatcher_(dispatcher) {}
18: 
19: void ActiveStreamListenerBase::emitLogs(Network::ListenerConfig& config,
20:                                         StreamInfo::StreamInfo& stream_info) {
21:   stream_info.onRequestComplete();
22:   for (const auto& access_log : config.accessLogs()) {
23:     access_log->log({}, stream_info);
24:   }
25: }
26: 
27: void ActiveStreamListenerBase::newConnection(Network::ConnectionSocketPtr&& socket,
28:                                              std::unique_ptr<StreamInfo::StreamInfo> stream_info) {
29:   // Find matching filter chain.
30:   const auto filter_chain = config_->filterChainManager().findFilterChain(*socket, *stream_info);
31:   if (filter_chain == nullptr) {
32:     RELEASE_ASSERT(socket->connectionInfoProvider().remoteAddress() != nullptr, "");
33:     ENVOY_LOG(debug, "closing connection from {}: no matching filter chain found",
34:               socket->connectionInfoProvider().remoteAddress()->asString());
35:     stats_.no_filter_chain_match_.inc();
36:     stream_info->setResponseFlag(StreamInfo::CoreResponseFlag::NoRouteFound);
37:     stream_info->setResponseCodeDetails(StreamInfo::ResponseCodeDetails::get().FilterChainNotFound);
38:     emitLogs(*config_, *stream_info);
39:     socket->close();
40:     return;
41:   }
42: 
43:   socket->connectionInfoProvider().setListenerInfo(config_->listenerInfo());
44:   socket->connectionInfoProvider().setFilterChainInfo(filter_chain->filterChainInfo());
45: 
46:   auto transport_socket = filter_chain->transportSocketFactory().createDownstreamTransportSocket();
47:   auto server_conn_ptr = dispatcher().createServerConnection(
48:       std::move(socket), std::move(transport_socket), *stream_info);
49:   if (const auto timeout = filter_chain->transportSocketConnectTimeout();
50:       timeout != std::chrono::milliseconds::zero()) {
51:     server_conn_ptr->setTransportSocketConnectTimeout(
52:         timeout, stats_.downstream_cx_transport_socket_connect_timeout_);
53:   }
54:   server_conn_ptr->setBufferLimits(config_->perConnectionBufferLimitBytes());
55:   RELEASE_ASSERT(server_conn_ptr->connectionInfoProvider().remoteAddress() != nullptr, "");
56:   const bool empty_filter_chain = !config_->filterChainFactory().createNetworkFilterChain(
57:       *server_conn_ptr, filter_chain->networkFilterFactories());
58:   if (empty_filter_chain) {
59:     ENVOY_CONN_LOG(debug, "closing connection from {}: no filters", *server_conn_ptr,
60:                    server_conn_ptr->connectionInfoProvider().remoteAddress()->asString());
61:     server_conn_ptr->close(Network::ConnectionCloseType::NoFlush, "no_filters");
62:   }
63:   newActiveConnection(*filter_chain, std::move(server_conn_ptr), std::move(stream_info));
64: }
65: 
66: ActiveConnections::ActiveConnections(OwnedActiveStreamListenerBase& listener,
67:                                      const Network::FilterChain& filter_chain)
68:     : listener_(listener), filter_chain_(filter_chain) {}
69: 
70: ActiveConnections::~ActiveConnections() {
71:   // connections should be defer deleted already.
72:   ASSERT(connections_.empty());
73: }
74: 
75: ActiveTcpConnection::ActiveTcpConnection(ActiveConnections& active_connections,
76:                                          Network::ConnectionPtr&& new_connection,
77:                                          TimeSource& time_source,
78:                                          std::unique_ptr<StreamInfo::StreamInfo>&& stream_info)
79:     : stream_info_(std::move(stream_info)), active_connections_(active_connections),
80:       connection_(std::move(new_connection)),
81:       conn_length_(new Stats::HistogramCompletableTimespanImpl(
82:           active_connections_.listener_.stats_.downstream_cx_length_ms_, time_source)) {
83:   // We just universally set no delay on connections. Theoretically we might at some point want
84:   // to make this configurable.
85:   connection_->noDelay(true);
86:   auto& listener = active_connections_.listener_;
87:   listener.stats_.downstream_cx_total_.inc();
88:   listener.stats_.downstream_cx_active_.inc();
89:   listener.per_worker_stats_.downstream_cx_total_.inc();
90:   listener.per_worker_stats_.downstream_cx_active_.inc();
91: 
92:   // Active connections on the handler (not listener). The per listener connections have already
93:   // been incremented at this point either via the connection balancer or in the socket accept
94:   // path if there is no configured balancer.
95:   listener.parent_.incNumConnections();
96: }
97: 
98: ActiveTcpConnection::~ActiveTcpConnection() {
99:   ActiveStreamListenerBase::emitLogs(*active_connections_.listener_.config_, *stream_info_);
100:   auto& listener = active_connections_.listener_;
101:   listener.stats_.downstream_cx_active_.dec();
102:   listener.stats_.downstream_cx_destroy_.inc();
103:   listener.per_worker_stats_.downstream_cx_active_.dec();
104:   conn_length_->complete();
105: 
106:   // Active listener connections (not handler).
107:   listener.decNumConnections();
108: 
109:   // Active handler connections (not listener).
110:   listener.parent_.decNumConnections();
111: }
112: 
113: void ActiveTcpConnection::onEvent(Network::ConnectionEvent event) {
114:   ENVOY_CONN_LOG(trace, "tcp connection on event {}", *connection_, static_cast<int>(event));
115:   // Any event leads to destruction of the connection.
116:   if (event == Network::ConnectionEvent::LocalClose ||
117:       event == Network::ConnectionEvent::RemoteClose) {
118:     // NOTE: Transport failure reason is set in ConnectionImpl::closeSocket() before events
119:     // are raised, so it should already be available in stream_info_ at this point.
120:     active_connections_.listener_.removeConnection(*this);
121:   }
122: }
123: 
124: void OwnedActiveStreamListenerBase::removeConnection(ActiveTcpConnection& connection) {
125:   ENVOY_CONN_LOG(debug, "adding to cleanup list", *connection.connection_);
126:   ActiveConnections& active_connections = connection.active_connections_;
127:   ActiveConnectionPtr removed = connection.removeFromList(active_connections.connections_);
128:   dispatcher().deferredDelete(std::move(removed));
129:   // Delete map entry if and only if connections_ becomes empty.
130:   if (active_connections.connections_.empty()) {
131:     auto iter = connections_by_context_.find(&active_connections.filter_chain_);
132:     ASSERT(iter != connections_by_context_.end());
133:     // To cover the lifetime of every single connection, Connections need to be deferred deleted
134:     // because the previously contained connection is deferred deleted.
135:     dispatcher().deferredDelete(std::move(iter->second));
136:     // The erase will break the iteration over the connections_by_context_ during the deletion.
137:     if (!is_deleting_) {
138:       connections_by_context_.erase(iter);
139:     }
140:   }
141: }
142: 
143: ActiveConnections& OwnedActiveStreamListenerBase::getOrCreateActiveConnections(
144:     const Network::FilterChain& filter_chain) {
145:   ActiveConnectionCollectionPtr& connections = connections_by_context_[&filter_chain];
146:   if (connections == nullptr) {
147:     connections = std::make_unique<ActiveConnections>(*this, filter_chain);
148:   }
149:   return *connections;
150: }
151: 
152: void OwnedActiveStreamListenerBase::removeFilterChain(const Network::FilterChain* filter_chain) {
153:   auto iter = connections_by_context_.find(filter_chain);
154:   if (iter == connections_by_context_.end()) {
155:     // It is possible when listener is stopping.
156:   } else {
157:     auto& connections = iter->second->connections_;
158:     while (!connections.empty()) {
159:       connections.front()->connection_->close(Network::ConnectionCloseType::NoFlush,
160:                                               "filter_chain_is_being_removed");
161:     }
162:     // Since is_deleting_ is on, we need to manually remove the map value and drive the
163:     // iterator. Defer delete connection container to avoid race condition in destroying
164:     // connection.
165:     dispatcher().deferredDelete(std::move(iter->second));
166:     connections_by_context_.erase(iter);
167:   }
168: }
169: 
170: } // namespace Server
171: } // namespace Envoy
