168:   ResponseHeaderMapOptRef informationalHeaders() override;
169:   ResponseHeaderMapOptRef responseHeaders() override;
170:   ResponseTrailerMapOptRef responseTrailers() override;
171:   void setBufferLimit(uint64_t limit) override;
172:   uint64_t bufferLimit() override;
