174:   // Functions to set or get iteration state.
175:   bool canIterate() { return iteration_state_ == IterationState::Continue; }
176:   bool stoppedAll() {
177:     return iteration_state_ == IterationState::StopAllBuffer ||
178:            iteration_state_ == IterationState::StopAllWatermark;
179:   }
180:   void allowIteration() {
181:     ASSERT(iteration_state_ != IterationState::Continue);
182:     iteration_state_ = IterationState::Continue;
183:   }
184:   MetadataMapVector* getSavedRequestMetadata() {
185:     if (saved_request_metadata_ == nullptr) {
186:       saved_request_metadata_ = std::make_unique<MetadataMapVector>();
187:     }
188:     return saved_request_metadata_.get();
189:   }
190:   MetadataMapVector* getSavedResponseMetadata() {
191:     if (saved_response_metadata_ == nullptr) {
192:       saved_response_metadata_ = std::make_unique<MetadataMapVector>();
193:     }
194:     return saved_response_metadata_.get();
195:   }
