197:   Router::RouteConstSharedPtr getRoute() const;
198: 
199:   void sendLocalReply(Code code, absl::string_view body,
200:                       std::function<void(ResponseHeaderMap& headers)> modify_headers,
201:                       const absl::optional<Grpc::Status::GrpcStatus> grpc_status,
202:                       absl::string_view details);
203: 
204:   // A vector to save metadata when the current filter's [de|en]codeMetadata() can not be called,
205:   // either because [de|en]codeHeaders() of the current filter returns StopAllIteration or because
206:   // [de|en]codeHeaders() adds new metadata to [de|en]code, but we don't know
207:   // [de|en]codeHeaders()'s return value yet. The storage is created on demand.
208:   std::unique_ptr<MetadataMapVector> saved_request_metadata_{nullptr};
209:   std::unique_ptr<MetadataMapVector> saved_response_metadata_{nullptr};
210:   // The state of iteration.
211:   enum class IterationState : uint8_t {
212:     Continue,            // Iteration has not stopped for any frame type.
213:     StopSingleIteration, // Iteration has stopped for headers, 100-continue, or data.
214:     StopAllBuffer,       // Iteration has stopped for all frame types, and following data should
215:                          // be buffered.
216:     StopAllWatermark,    // Iteration has stopped for all frame types, and following data should
217:                          // be buffered until high watermark is reached.
218:   };
219:   FilterManager& parent_;
220:   IterationState iteration_state_{};
221: 
222:   const FilterContext filter_context_;
223: 
224:   // If the filter resumes iteration from a StopAllBuffer/Watermark state, the current filter
225:   // hasn't parsed data and trailers. As a result, the filter iteration should start with the
226:   // current filter instead of the next one. If true, filter iteration starts with the current
227:   // filter. Otherwise, starts with the next filter in the chain.
228:   bool iterate_from_current_filter_{};
229:   bool headers_continued_{};
230:   bool continued_1xx_headers_{};
231:   // If true, end_stream is called for this filter.
232:   bool end_stream_{};
233:   // If true, the filter has processed headers.
234:   bool processed_headers_{};
235: };
