1140:     struct FilterCallState {
1141:       static constexpr uint32_t DecodeHeaders   = 0x01;
1142:       static constexpr uint32_t DecodeData      = 0x02;
1143:       static constexpr uint32_t DecodeMetadata  = 0x04;
1144:       static constexpr uint32_t DecodeTrailers  = 0x08;
1145:       static constexpr uint32_t EncodeHeaders   = 0x10;
1146:       static constexpr uint32_t EncodeData      = 0x20;
1147:       static constexpr uint32_t EncodeMetadata  = 0x40;
1148:       static constexpr uint32_t EncodeTrailers  = 0x80;
1149:       // Encode1xxHeaders is a bit of a special state as 1xx
1150:       // headers may be sent during request processing. This state is only used
1151:       // to verify we do not encode1xx headers more than once per
1152:       // filter.
1153:       static constexpr uint32_t Encode1xxHeaders  = 0x100;
1154:       // Used to indicate that one of the following conditions is true:
1155:       // 1. The filter manager is processing the final [En|De]codeData frame.
1156:       // 2. The filter manager is in [En|De]codeHeaders and is processing a
1157:       //    header-only request or response.
1158:       static constexpr uint32_t EndOfStream = 0x200;
1159: 
1160:       // Masks for filter call state.
1161:       static constexpr uint32_t IsDecodingMask = DecodeHeaders | DecodeData | DecodeMetadata | DecodeTrailers;
1162:       static constexpr uint32_t IsEncodingMask = EncodeHeaders | Encode1xxHeaders | EncodeData | EncodeMetadata | EncodeTrailers;
1163:     };
1164:   // clang-format on
