560: Network::FilterStatus ConnectionManagerImpl::onNewConnection() {
561:   if (!read_callbacks_->connection().streamInfo().protocol()) {
562:     // For Non-QUIC traffic, continue passing data to filters.
563:     return Network::FilterStatus::Continue;
564:   }
565:   // Only QUIC connection's stream_info_ specifies protocol.
566:   Buffer::OwnedImpl dummy;
567:   createCodec(dummy);
568:   ASSERT(codec_->protocol() == Protocol::Http3);
569:   // Stop iterating through network filters for QUIC. Currently QUIC connections bypass the
570:   // onData() interface because QUICHE already handles de-multiplexing.
571:   return Network::FilterStatus::StopIteration;
572: }
