600: void ConnectionManagerImpl::onEvent(Network::ConnectionEvent event) {
601:   if (event == Network::ConnectionEvent::LocalClose) {
602:     stats_.named_.downstream_cx_destroy_local_.inc();
603:   }
604: 
605:   if (event == Network::ConnectionEvent::RemoteClose ||
606:       event == Network::ConnectionEvent::LocalClose) {
607: 
608:     std::string details;
609:     if (event == Network::ConnectionEvent::RemoteClose) {
610:       remote_close_ = true;
611:       stats_.named_.downstream_cx_destroy_remote_.inc();
612:       details = StreamInfo::ResponseCodeDetails::get().DownstreamRemoteDisconnect;
613:     } else {
614:       absl::string_view local_close_reason = read_callbacks_->connection().localCloseReason();
615:       ENVOY_BUG(!local_close_reason.empty(), "Local Close Reason was not set!");
616:       details = fmt::format(
617:           fmt::runtime(StreamInfo::ResponseCodeDetails::get().DownstreamLocalDisconnect),
618:           StringUtil::replaceAllEmptySpace(local_close_reason));
619:     }
